let triggerTime = parseFloat(msg.payload); // Zeit in Sekunden aus dem input
let timerId = flow.get('timerId') || null; // Holen des Timer-IDs aus dem Flow-Kontext
let endTime = flow.get('endTime') || Date.now() + triggerTime * 1000; // Endzeit aus Flow-Kontext oder neu berechnen

// Bestehenden Timer löschen, falls vorhanden
if (timerId) {
    clearInterval(timerId);
}

// Funktion zur Aktualisierung des Node-Status
function updateCountdown() {
    let remainingTime = Math.ceil((endTime - Date.now()) / 1000);
    if (remainingTime > 0) {
        node.status({fill:"red", shape:"ring", text:`Trigger in ${remainingTime}s`});
    } else {
        node.status({fill:"green", shape:"dot", text:"Triggered"});
        endTime = Date.now() + triggerTime * 1000; // Neu berechnen des Endzeitpunkts für kontinuierliche Wiederholungen
        node.send({payload: true}); // Sende 'true' bei Ablauf des Timers
    }
}

// Setzen des Intervall-Timers
timerId = setInterval(() => {
    updateCountdown();
}, 1000); // Jede Sekunde aktualisieren

// Speichern des Timer-IDs und des Endzeitpunkts im Flow-Kontext
flow.set('timerId', timerId);
flow.set('endTime', endTime);

// Initialer Aufruf zur Statusaktualisierung
updateCountdown();

return null; // Keine direkte Nachrichtenausgabe

// ENTITY_IDS: All entity names queried from Home Assistant are listed here.
// Change the values of the keys if the entity names in your Home Assistant configuration are different.
const ENTITY_IDS = {
    DTU_STATUS: "binary_sensor.opendtu_b69d10_status",
    POWER_SECOND_SOURCE: "sensor.hoymiles600_power", // replace by empty string (POWER_SECOND_SOURCE: "") if no other generation plant is available.
    POWER_PRIMARY_SOURCE: "sensor.wechselrichter_ac_leistung", // replace by empty string (POWER_PRIMARY_SOURCE: "") if no other generation plant is available.
    POWER_CONSUMPTION: "sensor.smartmeter_keller_sml_watt_summe",
    SOLARFLOW_ELECTRIC_LEVEL: "sensor.solarflow_800_pro_electric_level",
    SOLARFLOW_BATTERY_FILL: "sensor.solarflow_800_pro_available_kwh",
    SOLARFLOW_BATTERY_LIMIT_OUTPUT: "number.solarflow_800_pro_output_limit",
    SOLARFLOW_BATTERY_LIMIT_INFLOW: "number.solarflow_800_pro_input_limit",
    SOLARFLOW_BATTERY_SOC_MIN_LEVEL: "number.solarflow_800_pro_min_soc",
    SOLARFLOW_BATTERY_SOC_MAX_LEVEL: "number.solarflow_800_pro_soc_set",
    SOLARFLOW_BATTERY_MAX_OUTPUT: "sensor.solarflow_800_pro_inverse_max_power",
    INVERTER_PRODUCING: "binary_sensor.hoymiles600_producing",
    INVERTER_REACHABLE: "binary_sensor.hoymiles600_reachable",
    INVERTER_OFF_THRESHOLD: "input_number.ausschaltschwelle_wechselrichter",
    INVERTER_ON_THRESHOLD: "input_number.einschaltschwelle_wechselrichter",
    INVERTER_MAX_OUTPUT_POWER: "input_number.maximale_ausgangsleistung_wechselrichter",
    INVERTER_MAX_OUTPUT_AT_FULL_SOC: "input_number.maximale_ausgangsleistung_bei_soc_100",
    INVERTER_MAX_ZERO_INJECTION: "input_number.maximale_leistung_nulleinspeisung_wechselrichter",
    INVERTER_MIN_ZERO_INJECTION: "input_number.minimale_leistung_nulleinspeisung_wechselrichter",
    STATUS_ZERO_INJECTION: "input_boolean.status_nulleinspeisung",
    INVERTER_STATIC_OUTPUT_POWER: "input_number.statische_ausgangsleistung_wechselrichter",
    TIME_SOLAR_USAGE: "schedule.no_solar",
    SOLARFLOW_BATTERY_POWER_MODE: "select.solarflow_800_pro_ac_mode",
    SOLARFLOW_BATTERY_CURRENT_OUTPUT: "sensor.solarflow_800_pro_output_home_power",
    SOLARFLOW_BATTERY_CURRENT_INFLOW: "sensor.solarflow_800_pro_grid_input_power"
};

// nameMapping: Mapping of technical entity IDs to user-friendly key names for later usage in calculation.
const nameMapping = {
    [ENTITY_IDS.DTU_STATUS]: "dtuState",
    [ENTITY_IDS.POWER_PRIMARY_SOURCE]: "pwrPrimarySource",
    [ENTITY_IDS.POWER_SECOND_SOURCE]: "pwrSecondSource",
    [ENTITY_IDS.POWER_CONSUMPTION]: "pwrConsumption",
    [ENTITY_IDS.SOLARFLOW_ELECTRIC_LEVEL]: "socLevelBattery",
    [ENTITY_IDS.INVERTER_PRODUCING]: "invStateProducing",
    [ENTITY_IDS.INVERTER_REACHABLE]: "invStateReachable",
    [ENTITY_IDS.INVERTER_OFF_THRESHOLD]: "offThresholdInv",
    [ENTITY_IDS.INVERTER_ON_THRESHOLD]: "onThresholdInv",
    [ENTITY_IDS.INVERTER_MAX_OUTPUT_POWER]: "maxOutputPowerInv",
    [ENTITY_IDS.INVERTER_MAX_OUTPUT_AT_FULL_SOC]: "maxOutputAtFullSoc",
    [ENTITY_IDS.INVERTER_MAX_ZERO_INJECTION]: "maxOutputZeroInjection",
    [ENTITY_IDS.INVERTER_MIN_ZERO_INJECTION]: "minOutputZeroInjection",
    [ENTITY_IDS.STATUS_ZERO_INJECTION]: "statusZeroInjection",
    [ENTITY_IDS.INVERTER_STATIC_OUTPUT_POWER]: "staticInverterOutputPower",
    [ENTITY_IDS.SOLARFLOW_BATTERY_FILL]: "batteryAvailableEnergy",
    [ENTITY_IDS.SOLARFLOW_BATTERY_LIMIT_OUTPUT]: "batterySetLimitOutput",
    [ENTITY_IDS.SOLARFLOW_BATTERY_LIMIT_INFLOW]: "batterySetLimitInflow",
    [ENTITY_IDS.SOLARFLOW_BATTERY_CURRENT_OUTPUT]: "batteryCurrentOutput",
    [ENTITY_IDS.SOLARFLOW_BATTERY_CURRENT_INFLOW]: "batteryCurrentInflow",
    [ENTITY_IDS.TIME_SOLAR_USAGE]: "noSolarPowerPossible",
    [ENTITY_IDS.SOLARFLOW_BATTERY_SOC_MIN_LEVEL]: "minSocLevelBattery",
    [ENTITY_IDS.SOLARFLOW_BATTERY_SOC_MAX_LEVEL]: "maxSocLevelBattery",
    [ENTITY_IDS.SOLARFLOW_BATTERY_MAX_OUTPUT]: "maxDischargingBattery",
    [ENTITY_IDS.SOLARFLOW_BATTERY_POWER_MODE]: "batteryACPowerMode"
};

// Input array of msg.payload
let dataArray = msg.payload;

let sortedData = {};
let missingDataWarnings = [];

// Converting and sorting the input array
dataArray.forEach(item => {
    let entityId = item.entity_id;
    if (nameMapping[entityId]) {
        let key = nameMapping[entityId];
        sortedData[key] = item.state;  // Here we extract only the ‘state’ from the item.
    }
});

// Check whether all required keys are present and whether warnings are necessary
Object.keys(ENTITY_IDS).forEach(key => {
    let entityId = ENTITY_IDS[key];
    let mappedKey = nameMapping[entityId];
    if (!sortedData[mappedKey] && entityId) {
        if (!["POWER_SECOND_SOURCE", "POWER_PRIMARY_SOURCE"].includes(key) || entityId !== "") {
            missingDataWarnings.push(mappedKey || key);
        }
    }
});

// Set the default value for power sources if no relevant data is available. Here only the value ‘0’ is set = no generation.
if (!sortedData["pwrSecondSource"]) {
    sortedData["pwrSecondSource"] = "0";
}
if (!sortedData["pwrPrimarySource"]) {
    sortedData["pwrPrimarySource"] = "0";
}

// Send warning messages if necessary
if (missingDataWarnings.length > 0) {
    node.warn("Fehlende Daten für: " + missingDataWarnings.join(", "));
    node.status({ fill: "red", shape: "dot", text: "Missing Data!" });
} else {
    // Set the node status to green to indicate that all data is valid and available.
    node.status({ fill: "green", shape: "dot", text: "Data is valid!" });
    node.send({ payload: sortedData });
}

// this function has 2 outputs (defined by returns):
// 1. Power Consumption is fine (0 - 15W) -> return no adjustment required
// 2. ELSE IF No Solar Power Possible == TRUE && trigger battery discharge exit
// 3. ELSE trigger battery charging exit

// Extracts HOAS data from formatted msg.payload
const pwrConsumption = Math.floor(parseFloat(msg.payload.pwrConsumption)); // Current Consumption in Watt
let noSolarPowerPossible = false;
if (msg.payload.noSolarPowerPossible == "on") // Schedule defining, if no reasonable solar power could be expected
{
    noSolarPowerPossible = true;   
}
// Expected and supported return values for succeeding nodes
let adjustCharging = null;
let adjustDischarging = null;
let debugMsg = null;

if (pwrConsumption >= 0 && pwrConsumption <= 15)
{
    debugMsg = { payload: `Power Consumption is fine, no adjustment required (value: ${pwrConsumption} )` };
}
else if (noSolarPowerPossible) 
{
    adjustDischarging = msg;
    debugMsg = { payload: `Power Consumption is not in ideal state(value: ${pwrConsumption} ), but no solar power expected, battery discharging triggered` };
}
else 
{
    adjustCharging = msg;
    debugMsg = { payload: `Power Consumption is not in ideal state(value: ${pwrConsumption} ), but solar power expected, battery charging triggered` };
}
return [adjustCharging, adjustDischarging, debugMsg];

// This node adjust the battery discharging process
// 1. IF Power Consumption is negative -> reduce output of battery by value - 5W
// 2. ELSE (Power Consumption is positive) -> increase output of batterie by value - 5W (limit max. 300W)

function createLogFileMsg(pwrConsumption, dischargingPower, socLevelBattery, minSocLevelBattery, currentOutputBattery, currentBatteryRemainingPower, maxDischargingBattery) {
    const now = new Date();
    const formattedTime = now.toLocaleString('de-DE', { hour12: false }); // Formatiert Zeit als 'Tag.Monat.Jahr Stunden:Minuten:Sekunden'

    // Converts floats to strings with german separator
    const formattedPwrConsumption = pwrConsumption.toLocaleString('de-DE');
    const formattedDischargePwr = dischargingPower.toLocaleString('de-DE');
    const formattedCurrentOutputPwr = currentOutputBattery.toLocaleString('de-DE');
    const formattedCurrentRemainingPwr = currentBatteryRemainingPower.toLocaleString('de-DE');

    return {
        payload: {
            "time": formattedTime,
            "pwrConsumption": formattedPwrConsumption,
            "socLevelBattery": socLevelBattery,
            "minSocLevelBattery": minSocLevelBattery,
            "currentOutputBattery": formattedCurrentOutputPwr,
            "dischargingPower": formattedDischargePwr,
            "maxDischargingBattery": maxDischargingBattery,
            "currentBatteryRemainingPower": formattedCurrentRemainingPwr
        }
    };
}

// Extracts HOAS data from formatted msg.payload
const pwrConsumption = Math.floor(parseFloat(msg.payload.pwrConsumption)); // Current Consumption in Watt
const socLevelBattery = parseFloat(msg.payload.socLevelBattery); // Current Charge level (SoC) of Battery in percent
const minSocLevelBattery = parseFloat(msg.payload.minSocLevelBattery); // minimal threshold the battery supports until stopping discharging
let currentOutputBattery = parseFloat(msg.payload.batteryCurrentOutput);
const currentBatteryRemainingPower = parseFloat(msg.payload.batteryAvailableEnergy);
const maxDischargingBattery = parseFloat(msg.payload.maxDischargingBattery);

// Expected and supported return values for succeeding nodes
let adjustSolarFlowDischarging = null;
let logFileMsg = null;
let debugMsg = null;
if (isNaN(parseFloat(msg.payload.batteryCurrentOutput)))
{
    currentOutputBattery = 0;
}
// calculate the necessary adaption
let dischargingPower = pwrConsumption + currentOutputBattery - 5;
if (isNaN(dischargingPower))
{
    dischargingPower = 0;
}
if(dischargingPower >= maxDischargingBattery)
{
    if(dischargingPower > pwrConsumption)
    {
        dischargingPower = pwrConsumption - 5;
        debugMsg = { payload: `Discharging is not in ideal state (current: ${currentOutputBattery}, power consumption ${pwrConsumption} ), i.e. adjust discharging to level of ${dischargingPower}` };
    }
    else
    {
        // limit to max discharging power the battery supports
        dischargingPower = maxDischargingBattery;
        debugMsg = { payload: `Discharging is not in ideal state (value: ${currentOutputBattery} ), i.e. adjust discharging to max. level of ${dischargingPower}` };
    }
}
if(dischargingPower < 0) {
    dischargingPower = 0;
}
// check if battery is already at limit, stop discharging
if(socLevelBattery - 3 < minSocLevelBattery)
{
    dischargingPower = 0;
    debugMsg = { payload: `Battery is empty, i.e. adjust discharging to ${dischargingPower}` };
}
if(dischargingPower != currentOutputBattery)
{
    // inform battery to adjust discharging accordingly because a new value is calculated
    adjustSolarFlowDischarging = { payload: dischargingPower };
    debugMsg = { payload: `Discharging is not in ideal state (value: ${currentOutputBattery} ), i.e. adjust discharging to ${dischargingPower}` };
}
logFileMsg = createLogFileMsg(pwrConsumption, dischargingPower, socLevelBattery, minSocLevelBattery, currentOutputBattery, currentBatteryRemainingPower, maxDischargingBattery);

return [adjustSolarFlowDischarging, debugMsg, logFileMsg];

// This node adjust the battery charging process
// 1. IF Power Consumption is negative -> increase input load of battery by value - 5W
// 2. ELSE (Current Input && Power Consumption is positive) -> decrease input load of batterie by value - 5W (limit max. 300W)

function createLogFileMsg(pwrConsumption, chargingPower, socLevelBattery, maxSocLevelBattery, currentOutputBattery, currentBatteryRemainingPower, maxChargingBattery) {
    const now = new Date();
    const formattedTime = now.toLocaleString('de-DE', { hour12: false }); // Formatiert Zeit als 'Tag.Monat.Jahr Stunden:Minuten:Sekunden'

    // Converts floats to strings with german separator
    const formattedPwrConsumption = pwrConsumption.toLocaleString('de-DE');
    const formattedChargePwr = chargingPower.toLocaleString('de-DE');
    const formattedCurrentOutputPwr = currentOutputBattery.toLocaleString('de-DE');
    const formattedCurrentRemainingPwr = currentBatteryRemainingPower.toLocaleString('de-DE');

    return {
        payload: {
            "time": formattedTime,
            "pwrConsumption": formattedPwrConsumption,
            "socLevelBattery": socLevelBattery,
            "maxSocLevelBattery": maxSocLevelBattery,
            "currentOutputBattery": formattedCurrentOutputPwr,
            "chargingPower": formattedChargePwr,
            "maxChargingBattery": maxChargingBattery,
            "currentBatteryRemainingPower": formattedCurrentRemainingPwr
        }
    };
}

// Extracts HOAS data from formatted msg.payload
const pwrConsumption = Math.floor(parseFloat(msg.payload.pwrConsumption)); // Current Consumption in Watt
const socLevelBattery = parseFloat(msg.payload.socLevelBattery); // Current Charge level (SoC) of Battery in percent
const maxSocLevelBattery = parseFloat(msg.payload.maxSocLevelBattery); // maximal threshold the battery supports until stopping charging
const minSocLevelBattery = parseFloat(msg.payload.minSocLevelBattery); // minimal threshold to keep the battery during solar on this SoC level
const currentInflowBattery = parseFloat(msg.payload.batteryCurrentInflow);
const currentBatteryRemainingPower = parseFloat(msg.payload.batteryAvailableEnergy);
let currentProductInverter1 = parseFloat(msg.payload.pwrPrimarySource);
let currentProductInverter2 = parseFloat(msg.payload.pwrSecondSource);
// norm not available DTU values
if(isNaN(currentProductInverter1))
{
    currentProductInverter1 = 0;
}
if(isNaN(currentProductInverter2))
{
    currentProductInverter2 = 0;
}
const producedPower = currentProductInverter1 + currentProductInverter2;
const maxChargingBattery = parseFloat(msg.payload.maxChargingBattery);
const setLimitInflowBattery  = parseFloat(msg.payload.batterySetLimitInflow);

// Expected and supported return values for succeeding nodes
let adjustSolarFlowCharging = null;
let logFileMsg = null;
let debugMsg = null;

// calculate the necessary adaption
// the power is: -200W
// setLimitInflowBattery = 200W
// currentInflowBattery = 100W
// => chargingPower = 100 - -200W = 300W

// the power is: 200W
// setLimitInflowBattery = 200W
// currentInflowBattery = 100W
// => chargingPower = 100 - 200W = -100W = 0W // set to min value of "0"
let chargingPower = currentInflowBattery - pwrConsumption;
if (chargingPower < 0)
{
    chargingPower = 0;
    debugMsg = { payload: `Currently too much usage. Stop charging (value: ${currentInflowBattery} ), would set ${chargingPower}W for charging.` };
}
else 
{
    debugMsg = { payload: `Currently too less power, or too much usage. No charging is possible (value: ${currentInflowBattery} ), i.e. adjust charging to max. level of ${chargingPower}` };
}

// check if the battery requires a loading because solar power is generated
if (socLevelBattery <= minSocLevelBattery && producedPower >= 150)
{
    if(chargingPower < producedPower) // only reset charging if not already charging is calculated
    {
        // set charging power to half of the solar power to charge until min level is reached
        chargingPower = producedPower / 2;
    }
}

if (chargingPower >= maxChargingBattery) {
    // limit to max discharging power the battery supports
    chargingPower = maxChargingBattery;
    debugMsg = { payload: `Charging is not ideal (value: ${currentInflowBattery} ), would set ${chargingPower}W for charging.` };
}
// check if battery is already at max. limit, stop charging
if (socLevelBattery + 1 >= maxSocLevelBattery) {
    chargingPower = 0;
    debugMsg = { payload: `Battery is full, i.e. adjust charging to ${chargingPower}` };
}
if (chargingPower != currentInflowBattery) {
    // inform battery to adjust discharging accordingly because a new value is calculated
    adjustSolarFlowCharging = { payload: chargingPower };
    debugMsg = { payload: `Charging is not as required (value: ${currentInflowBattery} ), i.e. adjust charging to ${chargingPower}` };
}
logFileMsg = createLogFileMsg(pwrConsumption, chargingPower, socLevelBattery, maxSocLevelBattery, currentInflowBattery, currentBatteryRemainingPower, maxChargingBattery);

return [adjustSolarFlowCharging, debugMsg, logFileMsg];
